import React, { useState } from 'react';
import {
  Box,
  Typography,
  Container,
  Button,
  Grid,
  Card,
  CardContent,
  useTheme,
  Paper,
  Divider,
  IconButton,
  TextField,
  InputAdornment,
  alpha,
  useMediaQuery,
} from '@mui/material';
import { useNavigate } from 'react-router-dom';
import {
  Timeline,
  Business,
  Security,
  Verified,
  ArrowForward,
  QrCodeScanner,
  LocalShipping,
  Search,
  KeyboardArrowDown,
} from '@mui/icons-material';
import { motion, AnimatePresence } from 'framer-motion';
import { useThemeContext } from '../contexts/ThemeContext';

// Define animation variants
const fadeIn = {
  hidden: { opacity: 0, y: 20 },
  visible: (i: number) => ({
    opacity: 1,
    y: 0,
    transition: {
      delay: i * 0.1,
      duration: 0.5,
      ease: 'easeOut'
    }
  })
};

const features = [
  {
    icon: <Timeline sx={{ fontSize: 50, color: '#4CAF50' }} />,
    title: 'Truy xuất nguồn gốc',
    description: 'Theo dõi toàn bộ quá trình từ sản xuất đến tiêu thụ sản phẩm',
    color: '#4CAF50',
    bgColor: 'rgba(76, 175, 80, 0.1)',
  },
  {
    icon: <Business sx={{ fontSize: 50, color: '#2196F3' }} />,
    title: 'Quản lý doanh nghiệp',
    description: 'Công cụ quản lý sản phẩm và chuỗi cung ứng cho doanh nghiệp',
    color: '#2196F3',
    bgColor: 'rgba(33, 150, 243, 0.1)',
  },
  {
    icon: <Verified sx={{ fontSize: 50, color: '#FF9800' }} />,
    title: 'Chứng nhận chất lượng',
    description: 'Xác thực và chứng nhận chất lượng sản phẩm',
    color: '#FF9800',
    bgColor: 'rgba(255, 152, 0, 0.1)',
  },
  {
    icon: <Security sx={{ fontSize: 50, color: '#9C27B0' }} />,
    title: 'Bảo mật thông tin',
    description: 'Sử dụng blockchain để đảm bảo tính minh bạch và không thể giả mạo',
    color: '#9C27B0',
    bgColor: 'rgba(156, 39, 176, 0.1)',
  },
];

const steps = [
  {
    icon: <QrCodeScanner sx={{ fontSize: 40 }} />,
    title: 'Quét mã QR',
    description: 'Quét mã QR trên sản phẩm để truy xuất thông tin',
  },
  {
    icon: <Timeline sx={{ fontSize: 40 }} />,
    title: 'Xem lịch sử',
    description: 'Theo dõi toàn bộ quá trình sản xuất và vận chuyển',
  },
  {
    icon: <Verified sx={{ fontSize: 40 }} />,
    title: 'Xác thực',
    description: 'Kiểm tra tính xác thực của sản phẩm và chứng nhận',
  },
];

const Home: React.FC = () => {
  const theme = useTheme();
  const navigate = useNavigate();

  const handleGetStarted = () => {
    navigate('/register');
  };

  return (
    <Box sx={{
      minHeight: '100vh',
      background: 'linear-gradient(135deg, #f5f7fa 0%, #e4efe9 100%)',
      overflow: 'hidden',
      position: 'relative'
    }}>
      {/* Background decorative elements */}
      <Box sx={{
        position: 'absolute',
        top: '10%',
        left: '5%',
        width: '300px',
        height: '300px',
        borderRadius: '50%',
        background: 'radial-gradient(circle, rgba(76, 175, 80, 0.1) 0%, rgba(76, 175, 80, 0) 70%)',
        zIndex: 0
      }} />
      <Box sx={{
        position: 'absolute',
        bottom: '15%',
        right: '10%',
        width: '250px',
        height: '250px',
        borderRadius: '50%',
        background: 'radial-gradient(circle, rgba(33, 150, 243, 0.1) 0%, rgba(33, 150, 243, 0) 70%)',
        zIndex: 0
      }} />

      <Container maxWidth="lg" sx={{ position: 'relative', zIndex: 1 }}>
        {/* Hero Section */}
        <Box sx={{ py: { xs: 6, md: 12 }, textAlign: 'center' }}>
          <motion.div
            initial="hidden"
            animate="visible"
            variants={fadeIn}
            custom={0}
          >
            <Typography
              variant="h2"
              component="h1"
              gutterBottom
              sx={{
                fontWeight: 700,
                background: 'linear-gradient(90deg, #4CAF50 0%, #2196F3 100%)',
                WebkitBackgroundClip: 'text',
                WebkitTextFillColor: 'transparent',
                mb: 3,
                fontSize: { xs: '2.5rem', md: '3.5rem' }
              }}
            >
              Hệ thống truy xuất nguồn gốc thực phẩm
            </Typography>
          </motion.div>

          <motion.div
            initial="hidden"
            animate="visible"
            variants={fadeIn}
            custom={1}
          >
            <Typography
              variant="h5"
              sx={{
                color: 'text.secondary',
                maxWidth: '800px',
                mx: 'auto',
                mb: 4,
                lineHeight: 1.6
              }}
            >
              Sử dụng công nghệ blockchain để đảm bảo tính minh bạch và an toàn cho chuỗi cung ứng thực phẩm
            </Typography>
          </motion.div>

          <motion.div
            initial="hidden"
            animate="visible"
            variants={fadeIn}
            custom={2}
            whileHover={{ scale: 1.05 }}
            whileTap={{ scale: 0.95 }}
          >
            <Button
              variant="contained"
              size="large"
              onClick={handleGetStarted}
              sx={{
                mt: 2,
                py: 1.5,
                px: 4,
                borderRadius: '50px',
                background: 'linear-gradient(90deg, #4CAF50 0%, #2196F3 100%)',
                boxShadow: '0 10px 20px rgba(76, 175, 80, 0.3)',
                fontWeight: 'bold',
                '&:hover': {
                  background: 'linear-gradient(90deg, #43A047 0%, #1E88E5 100%)',
                  boxShadow: '0 6px 15px rgba(76, 175, 80, 0.4)',
                }
              }}
              endIcon={<ArrowForward />}
            >
              Bắt đầu ngay
            </Button>
          </motion.div>
        </Box>

        {/* How it works section */}
        <Box sx={{ py: 8 }}>
          <motion.div
            initial="hidden"
            animate="visible"
            variants={fadeIn}
            custom={3}
          >
            <Typography
              variant="h4"
              align="center"
              gutterBottom
              sx={{
                fontWeight: 700,
                mb: 6,
                position: 'relative',
                display: 'inline-block',
                left: '50%',
                transform: 'translateX(-50%)',
                '&:after': {
                  content: '""',
                  position: 'absolute',
                  bottom: -10,
                  left: '25%',
                  width: '50%',
                  height: 4,
                  background: 'linear-gradient(90deg, #4CAF50 0%, #2196F3 100%)',
                  borderRadius: 2
                }
              }}
            >
              Cách thức hoạt động
            </Typography>
          </motion.div>

          <Grid container spacing={4} justifyContent="center">
            {steps.map((step, index) => (
              <Grid item xs={12} md={4} key={index}>
                <motion.div
                  initial="hidden"
                  animate="visible"
                  variants={fadeIn}
                  custom={index + 4}
                  whileHover={{ y: -10 }}
                >
                  <Paper
                    elevation={0}
                    sx={{
                      p: 4,
                      height: '100%',
                      display: 'flex',
                      flexDirection: 'column',
                      alignItems: 'center',
                      textAlign: 'center',
                      borderRadius: 4,
                      background: 'rgba(255, 255, 255, 0.8)',
                      backdropFilter: 'blur(10px)',
                      border: '1px solid rgba(255, 255, 255, 0.5)',
                      boxShadow: '0 10px 30px rgba(0, 0, 0, 0.05)',
                      position: 'relative',
                      overflow: 'hidden',
                      '&:before': {
                        content: '""',
                        position: 'absolute',
                        top: 0,
                        left: 0,
                        width: '100%',
                        height: '5px',
                        background: 'linear-gradient(90deg, #4CAF50 0%, #2196F3 100%)',
                      }
                    }}
                  >
                    <Box
                      sx={{
                        display: 'flex',
                        justifyContent: 'center',
                        alignItems: 'center',
                        width: 80,
                        height: 80,
                        borderRadius: '50%',
                        background: 'linear-gradient(135deg, rgba(76, 175, 80, 0.1) 0%, rgba(33, 150, 243, 0.1) 100%)',
                        mb: 3,
                      }}
                    >
                      <Typography
                        variant="h4"
                        sx={{
                          width: 40,
                          height: 40,
                          display: 'flex',
                          alignItems: 'center',
                          justifyContent: 'center',
                          borderRadius: '50%',
                          background: 'linear-gradient(90deg, #4CAF50 0%, #2196F3 100%)',
                          color: 'white',
                          fontWeight: 'bold',
                        }}
                      >
                        {index + 1}
                      </Typography>
                    </Box>
                    <Box sx={{ display: 'flex', justifyContent: 'center', mb: 2 }}>
                      {step.icon}
                    </Box>
                    <Typography variant="h6" gutterBottom fontWeight="bold">
                      {step.title}
                    </Typography>
                    <Typography color="text.secondary">
                      {step.description}
                    </Typography>
                  </Paper>
                </motion.div>
              </Grid>
            ))}
          </Grid>
        </Box>

        {/* Features Section */}
        <Box sx={{ py: 8 }}>
          <motion.div
            initial="hidden"
            animate="visible"
            variants={fadeIn}
            custom={7}
          >
            <Typography
              variant="h4"
              align="center"
              gutterBottom
              sx={{
                fontWeight: 700,
                mb: 6,
                position: 'relative',
                display: 'inline-block',
                left: '50%',
                transform: 'translateX(-50%)',
                '&:after': {
                  content: '""',
                  position: 'absolute',
                  bottom: -10,
                  left: '25%',
                  width: '50%',
                  height: 4,
                  background: 'linear-gradient(90deg, #4CAF50 0%, #2196F3 100%)',
                  borderRadius: 2
                }
              }}
            >
              Tính năng nổi bật
            </Typography>
          </motion.div>

          <Grid container spacing={4}>
            {features.map((feature, index) => (
              <Grid item xs={12} md={6} key={index}>
                <motion.div
                  initial="hidden"
                  animate="visible"
                  variants={fadeIn}
                  custom={index + 8}
                  whileHover={{ scale: 1.03 }}
                >
                  <Paper
                    elevation={0}
                    sx={{
                      p: 4,
                      height: '100%',
                      borderRadius: 4,
                      background: 'rgba(255, 255, 255, 0.8)',
                      backdropFilter: 'blur(10px)',
                      border: '1px solid rgba(255, 255, 255, 0.5)',
                      boxShadow: '0 10px 30px rgba(0, 0, 0, 0.05)',
                      overflow: 'hidden',
                      position: 'relative',
                      '&:before': {
                        content: '""',
                        position: 'absolute',
                        top: 0,
                        left: 0,
                        width: '5px',
                        height: '100%',
                        background: feature.color,
                      }
                    }}
                  >
                    <Box sx={{ display: 'flex', alignItems: 'flex-start' }}>
                      <Box
                        sx={{
                          display: 'flex',
                          justifyContent: 'center',
                          alignItems: 'center',
                          width: 80,
                          height: 80,
                          borderRadius: 3,
                          background: feature.bgColor,
                          mr: 3,
                          flexShrink: 0,
                        }}
                      >
                        {feature.icon}
                      </Box>
                      <Box>
                        <Typography variant="h5" gutterBottom fontWeight="bold" sx={{ color: feature.color }}>
                          {feature.title}
                        </Typography>
                        <Typography variant="body1" color="text.secondary" sx={{ lineHeight: 1.7 }}>
                          {feature.description}
                        </Typography>
                      </Box>
                    </Box>
                  </Paper>
                </motion.div>
              </Grid>
            ))}
          </Grid>
        </Box>

        {/* Call to action */}
        <Box sx={{ py: 10, textAlign: 'center' }}>
          <motion.div
            initial="hidden"
            animate="visible"
            variants={fadeIn}
            custom={12}
          >
            <Paper
              elevation={0}
              sx={{
                p: { xs: 4, md: 8 },
                borderRadius: 4,
                background: 'linear-gradient(135deg, rgba(76, 175, 80, 0.05) 0%, rgba(33, 150, 243, 0.05) 100%)',
                backdropFilter: 'blur(10px)',
                border: '1px solid rgba(255, 255, 255, 0.5)',
                boxShadow: '0 10px 30px rgba(0, 0, 0, 0.05)',
              }}
            >
              <Typography
                variant="h3"
                gutterBottom
                sx={{
                  fontWeight: 700,
                  fontSize: { xs: '2rem', md: '2.5rem' },
                  mb: 3
                }}
              >
                Sẵn sàng trải nghiệm?
              </Typography>
              <Typography
                variant="h6"
                color="text.secondary"
                sx={{
                  maxWidth: '800px',
                  mx: 'auto',
                  mb: 4
                }}
              >
                Đăng ký ngay hôm nay để bắt đầu truy xuất nguồn gốc sản phẩm và tham gia vào hệ sinh thái minh bạch
              </Typography>
              <motion.div
                whileHover={{ scale: 1.05 }}
                whileTap={{ scale: 0.95 }}
              >
                <Button
                  variant="contained"
                  size="large"
                  onClick={handleGetStarted}
                  sx={{
                    py: 1.5,
                    px: 6,
                    borderRadius: '50px',
                    background: 'linear-gradient(90deg, #4CAF50 0%, #2196F3 100%)',
                    boxShadow: '0 10px 20px rgba(76, 175, 80, 0.3)',
                    fontWeight: 'bold',
                    fontSize: '1.1rem',
                    '&:hover': {
                      background: 'linear-gradient(90deg, #43A047 0%, #1E88E5 100%)',
                      boxShadow: '0 6px 15px rgba(76, 175, 80, 0.4)',
                    }
                  }}
                  endIcon={<ArrowForward />}
                >
                  Đăng ký ngay
                </Button>
              </motion.div>
            </Paper>
          </motion.div>
        </Box>

        {/* Footer */}
        <Box sx={{ py: 4, textAlign: 'center' }}>
          <Divider sx={{ mb: 4 }} />
          <Typography variant="body2" color="text.secondary">
            © {new Date().getFullYear()} FoodTrace. Hệ thống truy xuất nguồn gốc thực phẩm.
          </Typography>
        </Box>
      </Container>
    </Box>
  );
};

export default Home;
